values.value:
{
  "keyField": "Id",
  "variant": "timeline",
  "stacked":true,
  "title": { "fieldName": "Subject", "label": "Subject", "action": "showDetails", "sortable": true, "lookup": "Id" },
  "icon": { "fieldName": "TypeIcon__c", "size": "small" },
  "columns": [
    { "fieldName": "Status", "label": "Status", "sortable": true },
    { "fieldName": "ActivityDate", "label": "Due Date", "type": "date-local", "sortable": true },
    { "type": "lookup", "fieldName": "Owner.Name", "label": "Owner", "typeAttributes": { "lookup": { "fieldName": "OwnerId" } },"sortable": true }
  ],
  "details": [
    { "fieldName": "Description", "label": "Description", "wrapText": true },
    { "fieldName": "TypeName__c", "label": "Type",  "sortable": true }
  ],
  "isDynamicMenu":true,
  "menu": [
    { "name": "closeActivity", "label": "Close", "iconName": "utility:check",
       "hidden": {"fieldName":"IsClosed__c"}},
    { "name": "editActivity", "label": "Edit", "iconName": "utility:edit" }
  ],
  "emptyMsg": "No activity found in the last 7 days.",
  "emptyVariant": "info"
}

{
  "Tasks": "SELECT Id, Subject, TypeIcon__c, Status, IsClosed, ActivityDate, Description, OwnerId, Owner.Name, TypeName__c, IsClosed__c FROM Task WHERE WhatId = '{{{ID}}}' AND (CreatedDate >= LAST_N_DAYS:7 OR IsClosed = true) ORDER BY ActivityDate DESC NULLS LAST",
  "Events": "SELECT Id, Subject, TypeIcon__c, ActivityDate, Description, OwnerId, Owner.Name, TypeName__c, IsClosed__c FROM Event WHERE WhatId = '{{{ID}}}' AND CreatedDate >= LAST_N_DAYS:7 ORDER BY ActivityDate DESC NULLS LAST"
}
